<template>
  <div class="flex justify-center">
    <div :style="{backgroundColor:'transparent', lineHeight:0}"
         class="p-4 rounded-full w-16 h-16 circle">
      <div class="colored-circle"></div>
      <font-awesome-icon
          class="icon-custom"
          :style="{zIndex:10, ...iconColors}"
          :icon="icon"/>
    </div>
  </div>
</template>

<script>
export default {
  name: "RoundedIcon",
  props:{
    icon:{
      required:true,
      type:String
    },
    color:{
      default:'#111'
    }
  },
  computed:{
    iconColors(){
      const values = this.color.replace('#','').split('');
      while (values.length < 3) {
        values.unshift(0);
      }
      return {
        '--color':this.color,
        '--reverted-color':'#' + values.map( x => (15 - parseInt(x,16)).toString(16)).join('')
      }
    }
  }
}
</script>

<style scoped lang="less">
  .circle{
    position: relative;
    &>*{
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%,-50%);
    }

  }
  .hovered-section{
    .colored-circle{
      min-height: 4rem;
      min-width: 4rem;
      border: 3px solid #333;
    }
    .icon-custom{
      color: var(--reverted-color);
      font-size: 25px;
    }
  }

  .icon-custom{
    color: var(--color);
    transition: color .2s ease, font-size .2s ease;
    font-size: 35px;
  }


  .colored-circle{
    min-width: 0;
    min-height: 0;
    position: absolute;
    z-index: 2;
    background: dimgray;
    border-radius: 100%;
    transition: min-width .3s ease, min-height .3s ease;
  }

</style>

