<template>
    <div class="mb-10 card" :class="{'hovered-section':hovered}" @mouseenter="hoverin" @mouseleave="hoverout">
      <slot></slot>
    </div>
</template>

<script>
export default {
  name: "Section",
  data:() => ({
    hovered:false
  }),
  methods:{
    hoverin(event){
      this.hovered = true;
      event.stopPropagation();
    },
    hoverout(event){
      this.hovered = false;
      event.stopPropagation();
    }
  }
}
</script>

<style scoped>

  .card{
    padding: 20px;
    margin: 3px 0;
    box-sizing: border-box;
    box-shadow: #FFF 0 0 6px;
    border: 1px solid #fff;
    transition: .2s border ease, .2s box-shadow ease;
  }

  .hovered-section.card{
    border: 1px solid #DDD;
    border-radius: 4px;
    box-shadow: #DDD 0 0 6px;
  }

</style>
